export function addForm(){document.getElementById("demo-container").innerHTML='\n    <form>\n      <div class="form-floating mb-3">\n        <input type="email" class="form-control" id="floatingInput" placeholder="name@example.com">\n        <label for="floatingInput">Email address</label>\n      </div>\n      <div class="form-floating mb-3">\n        <input type="password" class="form-control" id="floatingPassword" placeholder="Password">\n        <label for="floatingPassword">Password</label>\n      </div>\n      <div class="mb-3">\n        <label for="exampleInputEmail1" class="form-label">Email address</label>\n        <input type="email" class="form-control" id="exampleInputEmail1" aria-describedby="emailHelp">\n        <div id="emailHelp" class="form-text">We\'ll never share your email with anyone else.</div>\n      </div>\n      <div class="mb-3">\n        <label for="exampleInputPassword1" class="form-label">Password</label>\n        <input type="password" class="form-control" id="exampleInputPassword1">\n      </div>\n      <div class="mb-3 form-check">\n        <input type="checkbox" class="form-check-input" id="exampleCheck1">\n        <label class="form-check-label" for="exampleCheck1">Check me out</label>\n      </div>\n      <div class="mb-3">\n        <div class="form-check form-check-inline">\n          <input class="form-check-input" type="checkbox" id="inlineCheckbox1" value="option1">\n          <label class="form-check-label" for="inlineCheckbox1">1</label>\n        </div>\n        <div class="form-check form-check-inline">\n          <input class="form-check-input" type="checkbox" id="inlineCheckbox2" value="option2">\n          <label class="form-check-label" for="inlineCheckbox2">2</label>\n        </div>\n        <div class="form-check form-check-inline">\n          <input class="form-check-input" type="checkbox" id="inlineCheckbox3" value="option3" disabled>\n          <label class="form-check-label" for="inlineCheckbox3">3 (disabled)</label>\n        </div>\n      </div>\n      <div class="mb-3">\n        <div class="form-check">\n          <input class="form-check-input" type="checkbox" value="" id="flexCheckIndeterminate">\n          <label class="form-check-label" for="flexCheckIndeterminate">\n            Indeterminate checkbox\n          </label>\n        </div>\n      </div>\n      <div class="mb-3">\n        <label for="formFile" class="form-label">Default file input example</label>\n        <input class="form-control" type="file" id="formFile">\n      </div>\n      <div class="mb-3">\n        <label for="formFileMultiple" class="form-label">Multiple files input example</label>\n        <input class="form-control" type="file" id="formFileMultiple" multiple>\n      </div>\n      <div class="mb-3">\n        <label for="formFileDisabled" class="form-label">Disabled file input example</label>\n        <input class="form-control" type="file" id="formFileDisabled" disabled>\n      </div>\n      <div class="mb-3">\n        <select class="form-select" aria-label="Default select example">\n          <option selected>Open this select menu</option>\n          <option value="1">One</option>\n          <option value="2">Two</option>\n          <option value="3">Three</option>\n        </select>\n      </div>\n      <div class="mb-3">\n        <div class="form-check">\n          <input class="form-check-input" type="radio" name="flexRadioDefault" id="flexRadioDefault1">\n          <label class="form-check-label" for="flexRadioDefault1">\n            Default radio\n          </label>\n        </div>\n        <div class="form-check">\n          <input class="form-check-input" type="radio" name="flexRadioDefault" id="flexRadioDefault2" checked>\n          <label class="form-check-label" for="flexRadioDefault2">\n            Default checked radio\n          </label>\n        </div>\n      </div>\n      <div class="mb-3">\n        <div class="form-check form-check-inline">\n          <input class="form-check-input" type="radio" name="inlineRadioOptions" id="inlineRadio1" value="option1">\n          <label class="form-check-label" for="inlineRadio1">1</label>\n        </div>\n        <div class="form-check form-check-inline">\n          <input class="form-check-input" type="radio" name="inlineRadioOptions" id="inlineRadio2" value="option2">\n          <label class="form-check-label" for="inlineRadio2">2</label>\n        </div>\n        <div class="form-check form-check-inline">\n          <input class="form-check-input" type="radio" name="inlineRadioOptions" id="inlineRadio3" value="option3" disabled>\n          <label class="form-check-label" for="inlineRadio3">3 (disabled)</label>\n        </div>\n      </div>\n      <div class="mb-3">\n        <div class="form-check form-check-reverse">\n          <input class="form-check-input" type="checkbox" value="" id="reverseCheck1">\n          <label class="form-check-label" for="reverseCheck1">\n            Reverse checkbox\n          </label>\n        </div>\n        <div class="form-check form-check-reverse">\n          <input class="form-check-input" type="checkbox" value="" id="reverseCheck2" disabled>\n          <label class="form-check-label" for="reverseCheck2">\n            Disabled reverse checkbox\n          </label>\n        </div>\n\n        <div class="form-check form-switch form-check-reverse">\n          <input class="form-check-input" type="checkbox" id="flexSwitchCheckReverse">\n          <label class="form-check-label" for="flexSwitchCheckReverse">Reverse switch checkbox input</label>\n        </div>\n      </div>\n      <div class="mb-3">\n        <div class="form-check form-switch">\n          <input class="form-check-input" type="checkbox" role="switch" id="flexSwitchCheckDefault">\n          <label class="form-check-label" for="flexSwitchCheckDefault">Default switch checkbox input</label>\n        </div>\n        <div class="form-check form-switch">\n          <input class="form-check-input" type="checkbox" role="switch" id="flexSwitchCheckChecked" checked>\n          <label class="form-check-label" for="flexSwitchCheckChecked">Checked switch checkbox input</label>\n        </div>\n        <div class="form-check form-switch">\n          <input class="form-check-input" type="checkbox" role="switch" id="flexSwitchCheckDisabled" disabled>\n          <label class="form-check-label" for="flexSwitchCheckDisabled">Disabled switch checkbox input</label>\n        </div>\n        <div class="form-check form-switch">\n          <input class="form-check-input" type="checkbox" role="switch" id="flexSwitchCheckCheckedDisabled" checked disabled>\n          <label class="form-check-label" for="flexSwitchCheckCheckedDisabled">Disabled checked switch checkbox input</label>\n        </div>\n      </div>\n      <div class="mb-3">\n        <label for="customRange1" class="form-label">Example range</label>\n        <input type="range" class="form-range" id="customRange1">\n      </div>\n      <div class="input-group mb-3">\n        <span class="input-group-text" id="basic-addon1">@</span>\n        <input type="text" class="form-control" placeholder="Username" aria-label="Username" aria-describedby="basic-addon1">\n      </div>\n\n      <div class="input-group mb-3">\n        <input type="text" class="form-control" placeholder="Recipient\'s username" aria-label="Recipient\'s username" aria-describedby="basic-addon2">\n        <span class="input-group-text" id="basic-addon2">@example.com</span>\n      </div>\n\n      <label for="basic-url" class="form-label">Your vanity URL</label>\n      <div class="input-group mb-3">\n        <span class="input-group-text" id="basic-addon3">https://example.com/users/</span>\n        <input type="text" class="form-control" id="basic-url" aria-describedby="basic-addon3">\n      </div>\n\n      <div class="input-group mb-3">\n        <span class="input-group-text">$</span>\n        <input type="text" class="form-control" aria-label="Amount (to the nearest dollar)">\n        <span class="input-group-text">.00</span>\n      </div>\n\n      <div class="input-group mb-3">\n        <input type="text" class="form-control" placeholder="Username" aria-label="Username">\n        <span class="input-group-text">@</span>\n        <input type="text" class="form-control" placeholder="Server" aria-label="Server">\n      </div>\n\n      <div class="input-group mb-3">\n        <span class="input-group-text">With textarea</span>\n        <textarea class="form-control" aria-label="With textarea"></textarea>\n      </div>\n      <button type="submit" class="btn btn-primary mb-3">Submit</button>\n    </form>\n  ';const indeterminateCheckbox=document.getElementById("flexCheckIndeterminate");indeterminateCheckbox&&(indeterminateCheckbox.indeterminate=!0),setTooltips()}